function Counter() {
  // BUG: plain variable, not state — React won't re-render when it changes
  let count = 0;

  const increment = () => { count = count + 1; };
  const decrement = () => { count = count - 1; };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '16px', padding: '40px', fontFamily: 'monospace' }}>
      <h2 style={{ margin: 0, color: '#e0e0e0' }}>Counter</h2>
      <span data-testid="count" style={{ fontSize: '3rem', fontWeight: 'bold', color: '#e94560' }}>{count}</span>
      <div style={{ display: 'flex', gap: '12px' }}>
        <button onClick={decrement} style={{ padding: '8px 20px', fontSize: '1.2rem', background: '#16213e', color: '#e0e0e0', border: '1px solid #e94560', borderRadius: '4px', cursor: 'pointer' }}>-</button>
        <button onClick={increment} style={{ padding: '8px 20px', fontSize: '1.2rem', background: '#e94560', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>+</button>
      </div>
    </div>
  );
}
